const listings = $('Has Results?').all();

return items.map((item, index) => {
  const original = listings[index]?.json || {};

  if (typeof original.images === 'string' && original.images.startsWith('{')) {
    original.images = original.images.slice(1, -1).split(',').filter(u => u);
  }

  try {
    const rawString = item.json.text || item.json.output;
    const cleanString = rawString.replace(/```json|```/g, '').trim();
    const aiData = JSON.parse(cleanString);

    const bullets = (aiData.highlights || []).map(h => `• ${h}`).join('\n');

    const d = { ...original, ...aiData };
    const price = d.warm_rent || d.cold_rent || d.price || '?';
    const loc = [d.city, d.zip_code, d.district].filter(Boolean).join(' ');

    d.tg_message = [
      `🏠 *${(d.title || '').replace(/[_*[\]()~`>#+\-=|{}.!]/g, '\\$&')}*`,
      `📍 ${loc}`,
      '',
      `💶 ${price} € warm`,
      `🚪 ${d.rooms || '?'} Zi  \\|  📐 ${d.living_space || '?'} m²`,
      `⭐ *Score: ${d.score}/10*`,
      '',
      bullets.replace(/[_*[\]()~`>#+\-=|{}.!]/g, '\\$&'),
      '',
      `🔗 [Anzeige öffnen \\(${d.portal}\\)](${d.url})`,
    ].join('\n');

    return { json: d };
  } catch (error) {
    return { json: { ...original, is_relevant: false, score: 0, reject_reason: 'AI parse error', tg_message: 'Error' } };
  }
});
